namespace sv_17d2e70779ce449a933581e1b79dd82f.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    DateTimeOffset Timestamp,
    string Description,
    string Location);

using sv_17d2e70779ce449a933581e1b79dd82f.Client.Models;

namespace sv_17d2e70779ce449a933581e1b79dd82f.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_17d2e70779ce449a933581e1b79dd82f.Client.Models;
using sv_17d2e70779ce449a933581e1b79dd82f.Client.Services;

namespace sv_17d2e70779ce449a933581e1b79dd82f.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 26, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), "Package picked up", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility", "Philadelphia, PA"),
                new(new DateTimeOffset(2026, 5, 22, 8, 15, 0, TimeSpan.Zero), "Departed facility", "Philadelphia, PA"),
                new(new DateTimeOffset(2026, 5, 23, 6, 45, 0, TimeSpan.Zero), "In transit", "Chicago, IL"),
            }),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), "Package picked up", "Seattle, WA"),
                new(new DateTimeOffset(2026, 5, 19, 16, 0, 0, TimeSpan.Zero), "Arrived at sorting facility", "Portland, OR"),
                new(new DateTimeOffset(2026, 5, 20, 11, 0, 0, TimeSpan.Zero), "Out for delivery", "San Francisco, CA"),
                new(new DateTimeOffset(2026, 5, 20, 14, 22, 0, TimeSpan.Zero), "Delivered", "San Francisco, CA"),
            }),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 23, 7, 0, 0, TimeSpan.Zero), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_17d2e70779ce449a933581e1b79dd82f.Client.Models;

namespace sv_17d2e70779ce449a933581e1b79dd82f.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API over HTTP.
/// Used when the component runs in WebAssembly.
/// </summary>
public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_17d2e70779ce449a933581e1b79dd82f.Client.Models
@using sv_17d2e70779ce449a933581e1b79dd82f.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracking> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_error is not null)
{
    <div class="error-container">
        <p class="error-message">@_error</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status History</h3>
        <table>
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Description</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _error;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _error = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — nothing to do.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _error = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _error = "Something went wrong loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

